/* RoomHash WebTorrent service worker.
 * Based on WebTorrent's worker protocol, with multi-tab response selection.
 */
let cancellable = false
const portTimeoutDuration = 5000
const responseGraceDuration = 500
const responseTimeoutDuration = 1500

self.addEventListener('install', () => self.skipWaiting())
self.addEventListener('activate', () => self.clients.claim())
self.addEventListener('fetch', (event) => {
  const response = routeRequest(event)
  if (response) event.respondWith(response)
})

function routeRequest(event) {
  const { url } = event.request
  const prefix = `${self.registration.scope}webtorrent/`
  if (!url.includes(prefix)) return null
  if (url.includes(`${prefix}keepalive/`)) return new Response()
  if (url.includes(`${prefix}cancel/`)) {
    return new Response(new ReadableStream({ cancel: () => { cancellable = true } }))
  }
  return serve(event.request)
}

async function selectClient(request) {
  const windows = await clients.matchAll({ type: 'window', includeUncontrolled: true })
  if (!windows.length) return null

  return new Promise((resolve) => {
    let settled = false
    let pending = windows.length
    let fallback = null
    let graceTimer = null
    const ports = []

    const finish = (choice) => {
      if (settled) return
      settled = true
      clearTimeout(graceTimer)
      clearTimeout(timeoutTimer)
      for (const port of ports) {
        if (port !== choice?.port) {
          try { port.postMessage(false) } catch { /* closed */ }
          port.onmessage = null
        }
      }
      resolve(choice)
    }

    const timeoutTimer = setTimeout(() => finish(fallback), responseTimeoutDuration)
    for (const client of windows) {
      const channel = new MessageChannel()
      const { port1, port2 } = channel
      ports.push(port1)
      port1.onmessage = ({ data }) => {
        if (settled) {
          try { port1.postMessage(false) } catch { /* closed */ }
          return
        }
        const candidate = { data, port: port1 }
        pending -= 1
        if (data?.status >= 200 && data.status < 400) {
          finish(candidate)
          return
        }
        fallback ||= candidate
        if (!pending) finish(fallback)
        else if (!graceTimer) graceTimer = setTimeout(() => finish(fallback), responseGraceDuration)
      }
      client.postMessage({
        url: request.url,
        method: request.method,
        headers: Object.fromEntries(request.headers.entries()),
        scope: self.registration.scope,
        destination: request.destination,
        type: 'webtorrent'
      }, [port2])
    }
  })
}

async function serve(request) {
  const selected = await selectClient(request)
  if (!selected) return new Response('No active torrent client', { status: 503 })
  const { data, port } = selected
  if (!data) return new Response('Torrent client did not respond', { status: 504 })
  let timeout = null
  const cleanup = () => {
    try { port.postMessage(false) } catch { /* closed */ }
    clearTimeout(timeout)
    port.onmessage = null
  }

  if (data.body !== 'STREAM') {
    cleanup()
    return new Response(data.body, data)
  }

  return new Response(new ReadableStream({
    pull(controller) {
      return new Promise((resolve) => {
        port.onmessage = ({ data: chunk }) => {
          if (chunk) controller.enqueue(chunk)
          else {
            cleanup()
            controller.close()
          }
          resolve()
        }
        if (!cancellable && request.destination !== 'document') {
          clearTimeout(timeout)
          timeout = setTimeout(() => {
            cleanup()
            resolve()
          }, portTimeoutDuration)
        }
        port.postMessage(true)
      })
    },
    cancel: cleanup
  }), data)
}
